        code: '#include <bits/stdc++.h>\nusing namespace std;\n\nstring alienOrder(vector<string>& words) {\n    unordered_map<char, unordered_set<char>> graph;\n    unordered_map<char, int> color; // 0=unvisited, 1=visiting, 2=done\n    for (auto& w : words) for (char c : w) { graph[c]; color[c] = 0; }\n    for (int i = 0; i < words.size()-1; i++) {\n        string& w1 = words[i], &w2 = words[i+1];\n        int minLen = min(w1.size(), w2.size());\n        if (w1.size() > w2.size() && w1.substr(0, minLen) == w2.substr(0, minLen)) return ""; // invalid\n        for (int j = 0; j < minLen; j++) {\n            if (w1[j] != w2[j]) { graph[w1[j]].insert(w2[j]); break; }\n        }\n    }\n    string result;\n    function<bool(char)> dfs = [&](char c) -> bool {\n        color[c] = 1;\n        for (char next : graph[c]) {\n            if (color[next] == 1) return false; // cycle\n            if (color[next] == 0 && !dfs(next)) return false;\n        }\n        color[c] = 2;\n        result += c; // post-order\n        return true;\n    };\n    for (auto& [c, _] : graph)\n        if (color[c] == 0 && !dfs(c)) return "";\n    reverse(result.begin(), result.end()); // reverse post-order = topological\n    return result;\n}',
