        code: '#include <bits/stdc++.h>\nusing namespace std;\n\nstring alienOrder(vector<string>& words) {\n    unordered_map<char, unordered_set<char>> graph;\n    unordered_map<char, int> inDegree;\n    // Initialize all characters\n    for (auto& w : words) for (char c : w) { graph[c]; inDegree[c] = 0; }\n    // Build edges from adjacent word comparisons\n    for (int i = 0; i < words.size()-1; i++) {\n        string& w1 = words[i], &w2 = words[i+1];\n        int minLen = min(w1.size(), w2.size());\n        if (w1.size() > w2.size() && w1.substr(0, minLen) == w2.substr(0, minLen))\n            return ""; // invalid: longer word before shorter prefix\n        for (int j = 0; j < minLen; j++) {\n            if (w1[j] != w2[j]) {\n                if (!graph[w1[j]].count(w2[j])) {\n                    graph[w1[j]].insert(w2[j]); // w1[j] comes before w2[j]\n                    inDegree[w2[j]]++;\n                }\n                break; // only first difference matters\n            }\n        }\n    }\n    // BFS topological sort\n    queue<char> q;\n    for (auto& [c, deg] : inDegree)\n        if (deg == 0) q.push(c);\n    string result;\n    while (!q.empty()) {\n        char c = q.front(); q.pop();\n        result += c;\n        for (char next : graph[c]) {\n            inDegree[next]--;\n            if (inDegree[next] == 0) q.push(next);\n        }\n    }\n    return result.size() == inDegree.size() ? result : ""; // cycle check\n}',
